```plantuml
@startuml
class Fruit {
  + show()
  + hide()
}

class SlidingFruit {
  + show() // animate - slide in
}

class RollingFruit {
  + show() // animate - roll in
}

class Banana #FFCCCC {
  + hide() // animate - fade out
}

class Apple #FFCCCC {
  + hide() // animate - fade out
}

class Orange {
  + hide() // animate - slide out
}

Fruit <|-- SlidingFruit
Fruit <|-- RollingFruit

SlidingFruit <|-- Banana
RollingFruit <|-- Apple
RollingFruit <|-- Orange
@enduml
```
